// -------------------------------------------------------
// Rate Limit Module Tests (isolado de mocks de outros testes)
// -------------------------------------------------------
describe('Rate Limit Module', () => {
  it('exports required functions', () => {
    return new Promise<void>((resolve, reject) => {
      jest.isolateModules(async () => {
        try {
          const mod = await import('@/lib/rate-limit');
          expect(mod.globalRateLimiter).toBeDefined();
          expect(mod.checkRateLimit).toBeDefined();
          expect(mod.applyRateLimit).toBeDefined();
          resolve();
        } catch (e) {
          reject(e);
        }
      });
    });
  });

  it('globalRateLimiter.check returns correct shape', () => {
    return new Promise<void>((resolve, reject) => {
      jest.isolateModules(async () => {
        try {
          const { globalRateLimiter } = await import('@/lib/rate-limit');
          const result = globalRateLimiter.check('test-key-integration-xyz');

          expect(result).toHaveProperty('success');
          expect(result).toHaveProperty('remaining');
          expect(result).toHaveProperty('limit');
          expect(typeof result.success).toBe('boolean');
          expect(typeof result.remaining).toBe('number');
          resolve();
        } catch (e) {
          reject(e);
        }
      });
    });
  });

  it('rate limiter allows first request', () => {
    return new Promise<void>((resolve, reject) => {
      jest.isolateModules(async () => {
        try {
          const { globalRateLimiter } = await import('@/lib/rate-limit');
          const uniqueKey = `test-${Date.now()}-${Math.random()}`;
          const result = globalRateLimiter.check(uniqueKey);

          expect(result.success).toBe(true);
          expect(result.remaining).toBeGreaterThan(0);
          resolve();
        } catch (e) {
          reject(e);
        }
      });
    });
  });
});

