// -------------------------------------------------------
// Health Dashboard API Contract Tests
// -------------------------------------------------------
describe('API Contract: /api/system/health-dashboard', () => {
  it('health-dashboard module exports GET handler', async () => {
    const mod = await import('@/app/api/system/health-dashboard/route');
    expect(mod.GET).toBeDefined();
    expect(typeof mod.GET).toBe('function');
  });

  it('GET returns valid dashboard response shape', async () => {
    const { GET } = await import('@/app/api/system/health-dashboard/route');
    const req = createMockRequest('/api/system/health-dashboard');
    const res = await GET(req);

    // Accept 200 (healthy/degraded) or 503 (unhealthy) — both are valid
    expect([200, 503]).toContain(res.status);

    const body = await res.json();
    // Core shape validation
    expect(body.overall).toBeDefined();
    expect(['healthy', 'degraded', 'unhealthy']).toContain(body.overall);
    expect(body.services).toBeDefined();
    expect(Array.isArray(body.services)).toBe(true);
    expect(body.resources).toBeDefined();
    expect(body.resources.cpu).toBeDefined();
    expect(body.resources.memory).toBeDefined();
    expect(body.resources.process).toBeDefined();
    expect(body.queue).toBeDefined();
    expect(body.api).toBeDefined();
    expect(body.timestamp).toBeDefined();
    expect(body.uptimeFormatted).toBeDefined();
  });

  it('resources contain expected numeric fields', async () => {
    const { GET } = await import('@/app/api/system/health-dashboard/route');
    const req = createMockRequest('/api/system/health-dashboard');
    const res = await GET(req);
    const body = await res.json();

    expect(typeof body.resources.cpu.cores).toBe('number');
    expect(body.resources.cpu.cores).toBeGreaterThan(0);
    expect(typeof body.resources.memory.totalMB).toBe('number');
    expect(body.resources.memory.totalMB).toBeGreaterThan(0);
    expect(typeof body.resources.process.uptimeSeconds).toBe('number');
  });
});

