// -------------------------------------------------------
// Data Export Engine Unit Tests
// -------------------------------------------------------
describe('Data Export Engine', () => {
  it('validateExportRequest rejects empty userId', async () => {
    const { validateExportRequest } = await import('@/lib/compliance/data-export');
    const result = validateExportRequest('', null);
    expect(result.valid).toBe(false);
    expect(result.reason).toBeDefined();
  });

  it('validateExportRequest allows first export', async () => {
    const { validateExportRequest } = await import('@/lib/compliance/data-export');
    const result = validateExportRequest('user-123', null);
    expect(result.valid).toBe(true);
  });

  it('validateExportRequest enforces cooldown', async () => {
    const { validateExportRequest } = await import('@/lib/compliance/data-export');
    const recentDate = new Date().toISOString();
    const result = validateExportRequest('user-123', recentDate);
    expect(result.valid).toBe(false);
    expect(result.reason).toContain('Aguarde');
  });

  it('formatExportFilename generates correct pattern', async () => {
    const { formatExportFilename } = await import('@/lib/compliance/data-export');
    const filename = formatExportFilename('user-abc', '2026-03-15T12:00:00Z');
    expect(filename).toBe('user-data-export-user-abc-2026-03-15.json');
  });

  it('isExportExpired returns true for past dates', async () => {
    const { isExportExpired } = await import('@/lib/compliance/data-export');
    const pastDate = new Date(Date.now() - 86400000).toISOString();
    expect(isExportExpired(pastDate)).toBe(true);
  });

  it('isExportExpired returns false for future dates', async () => {
    const { isExportExpired } = await import('@/lib/compliance/data-export');
    const futureDate = new Date(Date.now() + 86400000).toISOString();
    expect(isExportExpired(futureDate)).toBe(false);
  });

  it('summarizeExport returns correct structure', async () => {
    const { buildUserDataExport, summarizeExport } = await import('@/lib/compliance/data-export');
    const exportData = buildUserDataExport({
      userId: 'test-user',
      exportId: 'test-export',
      profile: {
        id: 'test-user', email: 'test@example.com', name: null,
        avatarUrl: null, createdAt: new Date().toISOString(),
        lastSignIn: null, provider: 'email', emailVerified: true,
      },
      projects: [],
      videos: [],
      settings: {
        language: 'pt-BR', theme: 'system', notifications: true,
        defaultVoice: null, defaultResolution: '1080p', onboardingCompleted: false,
      },
      activity: [],
      billing: null,
      storage: { totalBytes: 0, totalFiles: 0, breakdown: { videos: 0, images: 0, audio: 0, other: 0 } },
      requestedAt: new Date().toISOString(),
      processingTimeMs: 100,
    });

    const summary = summarizeExport(exportData);
    expect(summary.categories).toBeDefined();
    expect(summary.totalRecords).toBeGreaterThan(0);
    expect(typeof summary.estimatedSizeKB).toBe('number');
    expect(summary.projectCount).toBe(0);
    expect(summary.videoCount).toBe(0);
  });
});
